<?php
require_once __DIR__.'/includes/bootstrap.php';require_auth();$u=current_user($pdo);$uid=(int)$u['id'];$q=trim($_GET['q']??'');$tasks=[];$teams=[];$users=[];$comments=[];$attachments=[];if($q!==''){$like="%{$q}%";$s=$pdo->prepare("SELECT id,title,status,priority FROM tasks WHERE (user_id=? OR assigned_to=?) AND (title LIKE ? OR description LIKE ? OR category LIKE ? OR tags LIKE ?) ORDER BY updated_at DESC LIMIT 20");$s->execute([$uid,$uid,$like,$like,$like,$like]);$tasks=$s->fetchAll();$s=$pdo->prepare("SELECT DISTINCT t.id,t.name FROM teams t JOIN team_members tm ON tm.team_id=t.id WHERE tm.user_id=? AND t.name LIKE ? LIMIT 20");$s->execute([$uid,$like]);$teams=$s->fetchAll();$s=$pdo->prepare("SELECT DISTINCT u.name,u.email FROM users u JOIN team_members tm ON tm.user_id=u.id JOIN team_members mine ON mine.team_id=tm.team_id AND mine.user_id=? WHERE u.name LIKE ? OR u.email LIKE ? LIMIT 20");$s->execute([$uid,$like,$like]);$users=$s->fetchAll();$s=$pdo->prepare("SELECT c.body,c.task_id,u.name,t.title FROM task_comments c JOIN users u ON u.id=c.user_id JOIN tasks t ON t.id=c.task_id WHERE (t.user_id=? OR t.assigned_to=?) AND c.body LIKE ? LIMIT 20");$s->execute([$uid,$uid,$like]);$comments=$s->fetchAll();}$pageTitle='Global Search';$activePage='search';require __DIR__.'/includes/header.php';?>
<section class="hero-row"><div><p class="eyebrow">GLOBAL SEARCH</p><h2>Find anything.</h2><p>Search tasks, teams, members and comments.</p></div></section><form class="panel global-search-form"><input name="q" value="<?=e($q)?>" placeholder="Search across your workspace..." autofocus><button class="btn btn-primary">Search</button></form><?php if($q!==''):?><section class="search-results"><?php foreach([['Tasks',$tasks],['Teams',$teams],['Members',$users],['Comments',$comments]] as $group):?><article class="panel"><div class="panel-head"><h3><?=e($group[0])?></h3><span><?=count($group[1])?></span></div><?php foreach($group[1] as $x):?><div class="search-item"><div><strong><?=e($x['title']??$x['name']??'Result')?></strong><small><?=e($x['email']??$x['body']??$x['status']??'')?></small></div><?php if(isset($x['task_id'])):?><a href="tasks/view.php?id=<?=$x['task_id']?>">→</a><?php elseif(isset($x['id'])&&$group[0]==='Tasks'):?><a href="tasks/view.php?id=<?=$x['id']?>">→</a><?php elseif(isset($x['id'])):?><a href="teams/view.php?id=<?=$x['id']?>">→</a><?php endif;?></div><?php endforeach;?><?php if(!$group[1]):?><p class="muted">No results.</p><?php endif;?></article><?php endforeach;?><article class="panel"><div class="panel-head"><h3>Files</h3><span><?=count($attachments)?></span></div><?php foreach($attachments as $x):?><a class="search-item" href="tasks/view.php?id=<?=$x['task_id']?>"><div><strong><?=e($x['original_name'])?></strong><small><?=e($x['title'])?></small></div><span>→</span></a><?php endforeach;?><?php if(!$attachments):?><p class="muted">No files found.</p><?php endif;?></article>
</section><?php endif;?><?php require __DIR__.'/includes/footer.php';?>